declare
  v_rows jsonb := '[{"campaign_name":"NHS Trust - Contacts","source_file":"NHS Trust - Contacts - Last view used.xlsx","source_sheet":"NHS Trust - Contacts","source_row":2,"payload":{"Organisation Name":"West London NHS Trust","Account Priority":"Low","Prospecting":"Prospect","(Primary) 1. Contact First Name":"Samuel","(Primary) 1. Contact  Last Name":"Wood","(Primary) 1. Contact Title":"Senior Sustainability Manager","(Primary) 1. Personal LinkedIn":"https://www.linkedin.com/in/samuel-wood-pisep-aema-b3bb17184/","(Primary) 1. Direct Email - Work":"samuel.aema@westlondon.nhs.uk","(Primary) Contacts Location":"London, England, UK","2. Contact Firstname":"Kieth","2. Contact Lastname":"Judd","2. Contact Title":"Transport Supervisor","2. Personal LinkedIn":"https://www.linkedin.com/in/kieth-judd-7737b8b3/","2. Direct Dial - Mobile":"447799490687","2. Direct Email - Work":"kieth.judd@westlondon.nhs.uk","2. Contacts Location":"London, England, UK","Website":"https://www.westlondon.nhs.uk/","Org. LinkedIn":"https://www.linkedin.com/company/west-london-nhs-trust/"}},{"campaign_name":"NHS Trust - Contacts","source_file":"NHS Trust - Contacts - Last view used.xlsx","source_sheet":"NHS Trust - Contacts","source_row":3,"payload":{"Organisation Name":"Walsall Healthcare NHS Trust","Company Description":"**Company:** Walsall Healthcare NHS Trust / The Royal Wolverhampton NHS Trust **Contact:** Janet Smith, Joint Head of Sustainability **Call date:** Pending - re-engagement call planned **Outcome:** Follow up required\n\n **Summary:** Two separate trusts operating as a group model since January 2025 with a shared Group Chief Executive, shared Chair and joint strategy running to 2027. Janet Smith holds a joint sustainability remit across both organisations meaning any decision applies across both trusts simultaneously - higher value contact than a single-trust sustainability lead. Previous contact made several years ago via a former colleague which progressed to an appointment in October 2023 but did not convert. Green Plan has since been refreshed for both trusts. Re-engagement planned on the basis of the new Green Plan and the strengthened group structure.\n\n  \n\nSee Wolverhampton for up to date info","Account Priority":"Low","Prospecting":"Prospect","Website":"https://www.walsallhealthcare.nhs.uk/","Org. LinkedIn":"https://www.linkedin.com/company/walsallhcarenhs/"}},{"campaign_name":"NHS Trust - Contacts","source_file":"NHS Trust - Contacts - Last view used.xlsx","source_sheet":"NHS Trust - Contacts","source_row":4,"payload":{"Organisation Name":"University Hospitals Leicester NHS Trust","Account Priority":"Low","Prospecting":"Prospect","(Primary) 1. Contact First Name":"Samantha","(Primary) 1. Contact  Last Name":"Rose Stanhope","(Primary) 1. Contact Title":"Associate Director of Sustainability and Waste","(Primary) 1. Personal LinkedIn":"https://www.linkedin.com/in/samantha-rose-stanhope-5273b233/","(Primary) 1. Direct Dial - Mobile":"447764290640","(Primary) Contacts Location":"Wakefield, England, UK","2. Contact Firstname":"Claudia","2. Contact Lastname":"Holyroyd","2. Contact Title":"Head of Sustainability and Waste","2. Personal LinkedIn":"https://www.linkedin.com/in/claudia-holroyd-707aab124/","2. Direct Email - Work":"cholroyd@uhl-tr.nhs.uk","2. Contacts Location":"Lutterworth, England, UK","3. Contact First Name":"Ben","3. Contact Last Name":"Widdowson","3. Contact Title":"Director of Estates, Facilities & Sustainability","3. Personal LinkedIn":"https://www.linkedin.com/in/ben-widdowson-54793711/","3. Direct Dial - Mobile":"447917307563","3. Direct Email - Work":"ben.widdowson@uhl-tr.nhs.uk","3. Contacts Location":"Derbyshire, England, UK","Website":"https://www.uhleicester.nhs.uk/","Org. LinkedIn":"https://www.linkedin.com/company/university-hospitals-of-leicester-nhs-trust/"}},{"campaign_name":"NHS Trust - Contacts","source_file":"NHS Trust - Contacts - Last view used.xlsx","source_sheet":"NHS Trust - Contacts","source_row":5,"payload":{"Organisation Name":"University Hospitals Coventry and Warwickshire NHS Trust","Technology Stack":"Park for now Clive confirmed air quality monitoring sits in his remit but they already have live external monitoring via a university partnership on a long-term (~10 year) contract. Not looking to expand. Internal monitoring not relevant as they don''t own the building. Objections raised: Already have live monitoring, long-term contract, not looking to expand Next steps: Send opt-out link as agreed. Park -- re-engage only if contract situation changes.","Account Priority":"None","Prospecting":"Prospect","Website":"https://www.uhcw.nhs.uk/","Org. LinkedIn":"https://www.linkedin.com/company/nhsuhcw/"}},{"campaign_name":"NHS Trust - Contacts","source_file":"NHS Trust - Contacts - Last view used.xlsx","source_sheet":"NHS Trust - Contacts","source_row":6,"payload":{"Organisation Name":"United Lincolnshire Hospitals NHS Trust","Account Priority":"Low","Prospecting":"Prospect","Website":"https://www.ulh.nhs.uk/"}},{"campaign_name":"NHS Trust - Contacts","source_file":"NHS Trust - Contacts - Last view used.xlsx","source_sheet":"NHS Trust - Contacts","source_row":7,"payload":{"Organisation Name":"The Royal Wolverhampton NHS Trust","Company Description":"Janet is a Sustainability contact at a West Midlands NHS Trust that already has air quality sensors installed across major sites via West Midlands Combined Authority, providing real-time and historical hourly data. EMSOL had already presented to the trust via Teams roughly a year ago. Despite Janet acknowledging the attribution gap - she can see when spikes happen but not what''s causing them - air quality has been classified internally as nice to have rather than essential, with budget being directed elsewhere. Parked for 12 months with a proactive re-engagement diary note set for around May 2027","Account Priority":"Low","Prospecting":"Prospect","Website":"https://royalwolverhampton.nhs.uk/","Org. LinkedIn":"https://www.linkedin.com/company/the-royal-wolverhampton-nhs-trust/"}},{"campaign_name":"NHS Trust - Contacts","source_file":"NHS Trust - Contacts - Last view used.xlsx","source_sheet":"NHS Trust - Contacts","source_row":8,"payload":{"Organisation Name":"Surrey and Sussex Healthcare NHS Trust","Company Description":"Same Trust as Susie Vernon, no engagement since intital conversation weeks ago, 9 touch points since then\n\n  \n\nHave moved onto other contacts within their care without carbon plan - chiefly Oliver Slaughter","Account Priority":"Low","Prospecting":"Email Sent - Callback Needed","Closing":"Appointment Set","Appointment Set Date  - start":"2026-07-31 12:00","Account Research - Event Notes":"Patrick Blanche is currently splitting his time across two trusts - he has moved into a Director of Estates role at East Sussex Healthcare NHS Trust while remaining in an advisory capacity at Surrey and Sussex Healthcare NHS Trust. At SASH, the Green Plan sits under a long-standing arrangement with Sussex Community NHS Foundation Trust, and the incoming permanent Director of Estates - whose name Patrick doesn''t yet have but has offered to share once confirmed - will own it going forward. At ESHT the sustainability picture is still being established. No hard objections were raised, timing across June and July being the only barrier given holidays and a dual-role workload. A consultation has been booked for Friday 31st July at 12pm. Worth noting the Sussex Community connection - Amy Bourne and Oliver Slaughter are already in an active email thread following a connected call this week, meaning EMSOL now has simultaneous touchpoints across both the trust managing SASH''s Green Plan and the\nincoming contact who will own it directly. Patrick has committed to passing on the name of the permanent ESHT and SASH estates lead once known.","Website":"https://www.surreyandsussex.nhs.uk/","Org. LinkedIn":"https://www.linkedin.com/company/surrey-&-sussex-healthcare-nhs-trust/"}},{"camp